sql:
SELECT value
FROM data_warehouse
WHERE team_id = 1 AND season_id = 0 AND metric = 'losses';

external_knowledge:
- 'Recently dominated their leagues' refers to teams with a season end date after December 31, 2022, and a season rank of three or less.;
- 'Top teams' refers to those that have earned the most points in their respective seasons and have an average of more than 15 wins per season.;
- 'Winning streak' refers to teams that have won more than they have lost in the season.;
- 'Imports to be proud of' refers to teams with at least one successful data import for the season.

sql:
SELECT COUNT(*) 
FROM business_intelligence
WHERE team_id = 0 AND season_id = 0;

external_knowledge:
- 'specific season' refers to data from the season with a season_id of 0; 
- 'win records' include wins, losses, and ties; 
- 'winning percentage' is calculated as the ratio of wins to total games played; 
- 'overall rank' combines both winning percentage and the number of wins; 
- 'a certain user' means the one with user_id of 0; 
- 'allowed to see' means having a can_view value of 1 in the permissions table.

sql:
SELECT report_name, report_date
FROM business_intelligence
WHERE report_type = 'performance';

SELECT report_type, COUNT(*) AS report_count
FROM business_intelligence
GROUP BY report_type;
